sequence.script:
var policyPayload = JSON.parse(mc.getProperty("policyPayload"));
var inspection = JSON.parse(mc.getProperty("inspection"));
var payableResponse = JSON.parse(mc.getProperty("payableResponse"));
var auditResponse = JSON.parse(mc.getProperty("auditResponse"));

var now = new Date();

// Format date yyyy-MM-dd
function formatDate(d) {
    var month = '' + (d.getMonth() + 1);
    var day = '' + d.getDate();
    var year = d.getFullYear();

    if (month.length < 2) month = '0' + month;
    if (day.length < 2) day = '0' + day;

    return [year, month, day].join('-');
}

var payload = {
    reference: {
        referenceTypeCode: "CLAIM_APPLICATION"
    },
    quoteId: policyPayload.quote.quoteId,
    claimId: mc.getProperty("claimId"),
    postingDate: formatDate(now),
    ledgerEntryIdentifier: "GLE" + now.getTime(),
    payableIdentifier: payableResponse.payableIdentifier,
    auditIdentifier: auditResponse.auditIdentifier,
    ledgerStatusCode: "POSTED",
    ledgerEntry: [{
        accountCode: "CLAIM_EXPENSE",
        debitAmount: {
            amountValue: inspection.assessment.netPayableAmount,
            currencyCode: "USD"
        }
    }]
};

mc.setPayloadJSON(payload);
